package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testGetRecordSeparator_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertEquals("\r\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_CustomString() {
        CSVFormat format = CSVFormat.DEFAULT.withRecordSeparator("|\n");
        assertEquals("|\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_CustomChar() {
        CSVFormat format = CSVFormat.DEFAULT.withRecordSeparator('\n');
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_Null() throws Exception {
        // Use reflection to create CSVFormat with null recordSeparator
        Class<?> quoteModeClass = Class.forName("org.apache.commons.csv.CSVFormat$QuoteMode");
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
            char.class, Character.class, quoteModeClass, Character.class, Character.class,
            boolean.class, boolean.class, String.class, String.class,
            Object[].class, String[].class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(
            ',', null, null, null, null, false, true, null, null, null, null, false, false, false);
        assertNull(format.getRecordSeparator());
    }
}
